var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하아…. 믿을 수 없어.","JPN":"はあ……信じられない。","ENG":"*Sigh...* This is ridiculous.","TWN":"蛤……真不敢相信。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"최고의 엘리트가 되어야 할 내가 이런 평범한 수업이나 들어야 한다니….","JPN":"最高のエリートになるはずの私が、こんな平凡な授業を受けないといけないなんて……","ENG":"I can't believe an elite like me has to take this boring class...","TWN":"要成為最頂尖精英的我，居然還要上這種普通的課……"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"방금 그 말. 선생님이 들으셨으면 엄청 슬퍼하셨을거야.","JPN":"今の言葉、先生が聞いたらすごく悲しんでたよ。","ENG":"You know, the teacher would be so heartbroken to hear that.","TWN":"剛才那句話，如果老師聽到了會非常傷心的。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 너하고 나밖에 없으니까 상관없잖아.","JPN":"でも今はあんたと私しかいないから別にいいんじゃない。","ENG":"It's only you and me, so it's fine.","TWN":"現在這裡只有你和我，所以無所謂吧。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"난 빨리 모의 전투 랭킹 1위를 달성해야 한다고.","JPN":"私は早く模擬戦闘でランキング1位を取らないといけないの。","ENG":"I need to reach number 1 on the simulation training leaderboard as fast as possible.","TWN":"我必須儘快達到模擬戰鬥的排名第一。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이대로 가다간, 너 처럼 지나가는 학생A나 다름 없어진단 말이야.","JPN":"このままだと、あんたみたいに通りすがりの生徒Aになっちゃう。","ENG":"At this rate, I'll be just another student in the crowd like you.","TWN":"照這樣下去，我就會變成像你一樣的路人甲了。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야 넌 꼭 말을 그런 식으로 해야겠니?","JPN":"そんな言い方、ひどいじゃない！","ENG":"Hey, was it necessary to say it like that?","TWN":"喂，你一定要那樣說話嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흐, 흥…….","JPN":"ふ、ふん……","ENG":"H-hmph...","TWN":"哼，哼……"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"후~ 이대로 내버려두면 끝도 없겠어.","JPN":"ふう……こんなやり取り、きりがないね。","ENG":"*Sigh* It'll never end if I leave her like this.","TWN":"呼～這樣下去沒完沒了。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"……있지. 나이엘은 지금까지 엄청 열심히 해왔잖아.","JPN":"……ねえ、ナイエルは今まですごく頑張ってきたじゃない。","ENG":"...Hey. You've done so much until now, Naielle.","TWN":"……你看，奈爾一直以來都非常努力。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오래 본 사이니까 잘 알아. 그 점은 나도 높이 사고 있어.","JPN":"長い付き合いだからわかる。あなたのそんなところはあたしもすごいと思うよ。","ENG":"I know because we've known each other for a long time. And I think highly of that part of you.","TWN":"因為我們認識很久了，所以我很了解你。這一點我也很看重。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그러니까 가끔은 좀 쉬어 가는 것도 좋지 않을까?","JPN":"だから、たまには少し一息ついてもいいんじゃないかな？","ENG":"So, wouldn't it be good to take a break sometimes?","TWN":"所以偶爾休息一下也不錯吧？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 수업 때 하루 종일 자고 있던 것도, 특별히 못 본 거로 해줄게!","JPN":"今日の授業中ずっと寝てたことも、特別に目を瞑ってあげるから！","ENG":"I'll even pretend I didn't see you sleeping all day during class today!","TWN":"今天上課你一直在睡覺的事，我就當作沒看見吧！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이게 지금 날 놀리겠다는 거야 뭐야?","JPN":"それって私をバカにしてない？","ENG":"Are you mocking me or something?","TWN":"你這是在耍我嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아참, 그러고 보니 곧 새로운 시스템이 도입된다고 들었는데……!","JPN":"あ、そういえば近いうちに新しいシステムが導入されるらしいけど……","ENG":"Oh, right. I heard a new system will be implemented soon...!","TWN":"啊，對了，聽說馬上要引入新的系統了……！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"너도 나름 학생회원이잖아. 뭔가 아는 거 없어?","JPN":"あんたも一応生徒会の一員でしょ？　なにか知ってる？","ENG":"You're in the Student Council, right? Don't you know anything about it?","TWN":"你也是學會成員吧，難道你什麼都不知道嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그게 지금 물어보는 태도야?","JPN":"それが人に質問する態度なの？","ENG":"How about you ask a little more politely?","TWN":"你現在這是問問題的態度嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아는 게 있으면 전부 말해!","JPN":"知ってるなら全部話してよ！","ENG":"Tell me everything you know!","TWN":"知道什麼就全都說出來！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으앗, 지, 진정해!","JPN":"わあ、お、落ち着いて！","ENG":"Eesh, c-calm down!","TWN":"啊，冷、冷靜！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"휴……. 어쩔 수 없지.","JPN":"はあ……仕方ないね。","ENG":"*Sigh* Fine.","TWN":"呼……沒辦法了。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"지금까지 성실히 봉사활동 했으니까 알려줄게. 진짜 비밀이다?\xA0","JPN":"今まで真面目にボランティアやってくれたから、教えてあげる。他の人には内緒だからね？\xA0","ENG":"I'll tell you only because you did well in your volunteering. But you have to keep it a secret, okay?\xA0","TWN":"到目前為止你一直在認真做志工活動，所以我才告訴你。這可是個真正的秘密喔？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 아카데미에 새로운 선생님 <color=#ffd34c>두 분</color>이 오시는 건 알지?","JPN":"今日アカデミーに新しい先生が<color=#ffd34c>2人</color>来るってこと、知ってるよね？","ENG":"You know how there are <color=#ffd34c>two</color> new teachers coming to the Academy today, right?","TWN":"今天有<color=#ffd34c>兩位</color>新老師要來學院，你知道嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>판도라</color> 회사. 들어본 적 있어?","JPN":"<color=#ffd34c>パンドラ</color>って会社、聞いたことある？","ENG":"Have you ever heard of a company called <color=#ffd34c>Pandora</color>?","TWN":"<color=#ffd34c>潘朵拉</color>公司。聽說過嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"설마 그 게임 회사 말하는 거야?","JPN":"まさかあのゲーム会社のこと？","ENG":"Are you talking about that game company?","TWN":"難道你在說那家遊戲公司嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>맞아, 카운터즈 시리즈를 만든 그 회사!</color>","JPN":"<color=#ffd34c>そうだよ。カウンターズシリーズを作ったあの会社！</color>","ENG":"<color=#ffd34c>Yeah, the company that made the Counters series!</color>","TWN":"<color=#ffd34c>沒錯，就是製作了制裁者系列的那家公司！</color>"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"게임 회사 직원이 왜 선생으로 오는 건데?","JPN":"ゲーム会社の社員がなんで先生として来るの？","ENG":"So, why is an employee from that game company coming here as a teacher?","TWN":"遊戲公司的員工為什麼會來當老師？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"알아봤는데 이번 시뮬레이션의 개발을 그곳에서 담당했다고 하더라.","JPN":"調べてみたら、新しいシミュレーションの開発をそこが担当したみたい。","ENG":"I looked into it, and the company was in charge of developing this new simulation system.","TWN":"我查了一下，這次模擬的開發是由那邊負責的。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이번에 오시는 선생님들이 그 판도라 사의 핵심 개발자시래!","JPN":"今回来る先生たちは、あのパンドラ社の中心的開発者なんだって！","ENG":"The teachers who are coming are core developers from Pandora!","TWN":"這次來的老師們是潘朵拉公司的核心開發人員！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"서론이 너무 길어! 그래서 그 업데이트란 게 뭔데?","JPN":"前置きが長すぎる！　で、そのアップデートって何なのよ？","ENG":"Cut to the chase, will you?! So, what's with the update?","TWN":"前言太長了！所以那個更新到底是什麼？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"지금 말하려던 참이었어. 그건……!","JPN":"今から話そうとしてるじゃない。それは……！","ENG":"I was just getting to that. It's–","TWN":"我正要說呢。那是……！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"서기 미카★스타 학생은 지금 즉시 이사장실로 와주시기 바랍니다.","JPN":"書記のミカ★スターさんは今すぐ理事長室に来てください。","ENG":"Clerk Mika★Star, please come to the Chairwoman's office immediately.","TWN":"米卡★斯塔同學請立即到理事長辦公室來。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아참, 내 정신 좀 봐!","JPN":"あっ！　忘れてた！","ENG":"Oh, dear! I completely forgot!","TWN":"啊對了，你看我的記性！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"빨리 가봐야겠다! 나머진 이따가 말해줄게~","JPN":"早く行かないと！　続きは後で話すね！","ENG":"I gotta go! I'll tell you the rest later!","TWN":"我得快點去了！剩下的待會兒再告訴你～"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"야, 실컷 궁금하게 해놓고 어디가! 학생회 녀석들은 왜 죄다 이러는데?!","JPN":"ちょっと！　そこからが大事なのにどこ行くのよ！　生徒会のやつらはなんでみんなこうなの！？","ENG":"Hey! You got me this invested and you're leaving?! Why do all the Student Council members do this?!","TWN":"喂，弔胃口吊足了我的胃口就想跑嗎！學生會的傢伙怎麼都這樣？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"역시 직접 가서 물어봐야겠어!","JPN":"やっぱり自分で確かめるしかないわね！","ENG":"I should just go ask her myself!","TWN":"果然還是要親自去問一下！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"분명 여기 앞이 이사장실이었지?","JPN":"確かここが理事長室だったよね？","ENG":"This should be the Chairwoman's office, right?","TWN":"這裡應該就是理事長辦公室吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무슨 꿍꿍이인지 다 파헤쳐주겠……!","JPN":"いったい何を企んでるのか、私が全部暴いてや……！","ENG":"I'll get to the bottom of thi–","TWN":"我會揭穿你所有的陰謀……！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"쟈, 쟘캰만요……! 이미 잔뜩 받았는데…….","JPN":"ま、待って……！　もうたくさんいただきましたから……","ENG":"W-wait...! I can't take anymore...","TWN":"等，等一下……！已經收到了很多了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"안 돼……. 입안에 있는데…… 말하면.","JPN":"喋っちゃダメ……口にものが入ってる。","ENG":"No... You shouldn't talk... with your mouth full.","TWN":"不，不……就在嘴邊……說出來。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"어때……? 마음에 들어……?","JPN":"どう……？　気に入った……？","ENG":"So...? Do you like it...?","TWN":"怎麼樣……？喜歡嗎……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"마무리로…… 마시는 거야……. 이걸.","JPN":"最後に……飲んで………これを。","ENG":"And to finish off... you'll need to drink... this.","TWN":"最後……喝下這個吧……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으읍……!","JPN":"ううっ……！","ENG":"MMMMPH...!","TWN":"唔……！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"마음에 들어……?","JPN":"気に入った……？","ENG":"Do you like it...?","TWN":"喜歡……嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"후훗, 미카한텐 아직 무리일 거야.","JPN":"ふふっ、ミカにはまだ早いかも。","ENG":"Ha hah, maybe it was too much for Mika.","TWN":"呵呵，看來米卡還是不行呢。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"호불호가 많이 갈려서, 지금까진 다른 학생들한테 권하지 않았거든.","JPN":"人によって反応が分かれるから、今まで他の生徒には勧めなかった。","ENG":"It's an acquired taste, and that's why I didn't offer it to students until now.","TWN":"口味這東西因人而異，所以我到現在還沒向其他學生推薦過。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이건 설마……?!","JPN":"こ、これはまさか……！？","ENG":"W-what's going on...?!","TWN":"這，這難道是……？！ "},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"굉장해요! 처음엔 어색했는데…… 왜 좋아하시는지 알 것 같아요.","JPN":"すごい！　はじめは違和感がありましたけど……お好きな理由がわかった気がします。","ENG":"That was amazing! It was a little awkward at first, but... I can see why people like it.","TWN":"太棒了！雖然一開始有點不習慣……但我現在明白你為什麼喜歡了。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"기뻐……. 취향에 잘 맞는 것 같아서.","JPN":"嬉しい……好みに合ったみたいで。","ENG":"I'm glad... that it suits your taste.","TWN":"很高興……看起來很合我的口味。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"그럼 이번엔…….","JPN":"じゃ、次は……","ENG":"Then, this time...","TWN":"那麼這次呢……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네?! 또요?","JPN":"え！？　またですか？","ENG":"What?! Again?","TWN":"什麼？！又來？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"못 들어주겠네 진짜!","JPN":"聞いてらんないなぁもう！","ENG":"Oh, come on!","TWN":"我聽不下去了！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미카! 지금 뭐 하는……!","JPN":"ミカ！　何やって……！","ENG":"Mika! What are you do–","TWN":"米卡！你在幹什麼……？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"나이엘? 여긴 어쩐 일이니?","JPN":"ナイエル？　どうしたの？","ENG":"Naielle? What brings you here?","TWN":"奈爾？你怎麼在這裡？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"후~ 맛있어라……. 나이엘도 한번 먹어볼래?","JPN":"はあ～おいしい……ナイエルも食べる？","ENG":"Whew, that was delicious... Care to try it, Naielle?","TWN":"呼～真好吃……奈爾也要嘗一口嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"머, 먹으라고?","JPN":"た、食べる？","ENG":"M-me?","TWN":"吃，吃掉嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선생님. 이거 나이엘한테도 줘도 될까요?","JPN":"先生、これナイエルにもあげていいですか？","ENG":"Do you mind if I give Naielle one?","TWN":"老師，這個可以給奈爾嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시, 싫어! 나한테 뭘 하려는……","JPN":"い、いやっ！　私に何するつもり……","ENG":"N-no! What are you going to do to me–","TWN":"不，不要！你想對我做什麼……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 으읍……!","JPN":"ちょ、ううっ……！","ENG":"Wait! Mmph...!","TWN":"等等，呃……！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"얼래? 그냥 과자였잖아……?","JPN":"あれ？　ただのお菓子……？","ENG":"Huh? It's just snacks...?","TWN":"咦？不就是餅乾嗎……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"설마 지금까지 여기서 과자 먹고 있던 거야?","JPN":"まさか、今までここでお菓子を食べてたの？","ENG":"Were you eating snacks this whole time?","TWN":"難道你一直在這裡吃零食嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 이사장님께서 새로 오신 선생님들 소개해 주신다고 하셨거든.","JPN":"うん。理事長が新しい先生を紹介してくれるって言ってね。","ENG":"Yup. Ms. Chairwoman said she would introduce the new teachers.","TWN":"嗯，理事長說要介紹新來的老師們。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 그렇게 말하던가!","JPN":"そ、それならそう言えばいいじゃない！","ENG":"W-well, you should've said that!","TWN":"你為何不早說啊！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"대체 무슨 생각을 했길래 그래?","JPN":"いったい何だと思ってたの？","ENG":"What did you think was going on?","TWN":"是你想多了吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그러니까….","JPN":"そ、それは……","ENG":"W-well...","TWN":"所，所以說……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"재밌는 아이네……. 듣던 대로.","JPN":"話どおり……面白い子。","ENG":"You're a quirky student... just as they've told me.","TWN":"真是個有趣的孩子……果然如傳聞所說。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_QM","text":{"KOREA":"네가 나이엘…… 맞지? 반가워.","JPN":"あなたがナイエル……だよね。よろしく。","ENG":"You're Naielle... right? Nice to meet you.","TWN":"你是奈爾……對吧？很高興見到你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"다, 당신은……?!","JPN":"あ、あんたは……！？","ENG":"W-who are you...?!","TWN":"你，你是……？！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"진보라라고 해……. 아카데미의 신임 강사.","JPN":"タカダ・シホ……アカデミーの新任講師。","ENG":"I'm Jin Bora... The new teacher coming to the Academy.","TWN":"我叫陳寶拉……是學院的新任講師。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"신임 강사……?","JPN":"新任講師……？","ENG":"New teacher...?","TWN":"新任講師……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"카운터즈 시리즈, 아까 말했지? 이분이 만든 거래!","JPN":"カウンターズシリーズ、さっき話したでしょ？　この方が作ったんだって！","ENG":"Remember the Counters series? She made it!","TWN":"制裁者系列，我剛才說過吧？是這位製作的！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"관심 없어. 왜 게임 개발자가 선생으로 온 거야?","JPN":"それはどうでもいい。なんでゲーム開発者が先生なの？","ENG":"I don't care. Why would a game developer come here as a teacher?","TWN":"沒興趣。為什麼遊戲開發者會來當老師？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"풍부하니까……. 경험.","JPN":"豊富だから……経験。","ENG":"Because I have lots of... experience.","TWN":"因為很豐富……在經驗這方面。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……?","JPN":"……","ENG":"...","TWN":"……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"카운터로서…… 실전 경험.","JPN":"カウンターとしての……実戦経験。","ENG":"Practical experience... as a Counter.","TWN":"作為制裁者……的實戰經驗。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"잘 가르쳐 줄게…… 너무 걱정하지 마.","JPN":"しっかり教えてあげる……心配しないで。","ENG":"I'll teach you well... so, no need to worry.","TWN":"我會好好教你的……不要太擔心。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 처음부터 그렇게 말하라고!","JPN":"そ、そういうことなら最初からそう言ってよ！","ENG":"Y-you should've said that from the start!","TWN":"那，那你一開始就應該這麼說啊！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"나이엘, 궁금한 게 많은 건 알겠지만. 조금은 예의를 지켜 주렴.","JPN":"ナイエル、気になることが多いのはわかるけど、礼儀は守りましょう。","ENG":"Naielle, I know you have a lot of questions, but please show some manners.","TWN":"奈爾，我知道你有很多問題，但請稍微注意一下禮貌。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"보라의 실력은 확실하니까, 너무 걱정하지 않아도 돼.","JPN":"シホちゃんの腕は確かだから、心配はいらないわよ。","ENG":"I can vouch for Bora's skills, so you don't have to worry about that.","TWN":"寶拉還是很有能力的，不用擔心。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하, 듣자 하니 인맥으로 들어왔다는 거 같은데, 맞지?","JPN":"ふん、見たとこ、コネで入ったんでしょ？","ENG":"*Scoff* It seems like you got the job through connections.","TWN":"哈？聽說你是靠關係進來的，對吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미안한데, 난 낙하산 같은 건 인정 안 하거든?","JPN":"悪いけど、私はそういうの認めないから。","ENG":"I'm sorry, but I don't think fondly of nepotism.","TWN":"抱歉，我可不承認什麼空降部隊。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"걱정 마…… 만족시켜 줄 테니까.","JPN":"大丈夫……満たしてあげる。","ENG":"Don't worry... I'll make sure to satisfy.","TWN":"別擔心……我會讓你滿意的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"마, 만족……? 대체 뭘……?!","JPN":"み、満たす……？　何を……！？","ENG":"S-satisfy...? Satisfy what...?!","TWN":"滿，滿意……？到底是……什麼……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"나이엘의 기준……?","JPN":"ナイエルの基準……？","ENG":"Naielle's standards...?","TWN":"奈爾的標準……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아오! 제발 좀 한 번에 알아듣게 말하라고!","JPN":"ああもう！　最初からわかるように言ってよ！","ENG":"Ugh! Could you just say it clearly the first time?!","TWN":"啊！拜託你可以一次說清楚嗎！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 뭐, 좋아.","JPN":"ふん！　まあ、いいわ。","ENG":"Hmph! Well, all right.","TWN":"哼！好，好。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"정말 내 기준을 만족시킬 수 있는지 두고 보자구!","JPN":"本当に私の基準を満たすことができるか、確認させてもらうから！","ENG":"Let's see if you'll be able to live up to my standards!","TWN":"就看看你能不能滿足我的標準吧！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 너 선생님한테 무슨 말버릇이야!","JPN":"もう、先生に失礼な言い方やめてよ！","ENG":"Hey! Watch your manners in front of our teacher!","TWN":"喂，你對老師什麼態度！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"죄송해요 선생님. 제가 따끔하게 말하고 올 게요.","JPN":"すみません、先生。あたしからちゃんと言っておきます。","ENG":"I'm sorry, ma'am. I'll make sure to give her an earful.","TWN":"對不起，老師。我會好好管教她的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"……좀 당황스러웠지? 괜찮아?","JPN":"……困惑したよね。大丈夫？","ENG":"...Sorry about that. Are you okay?","TWN":"……沒事吧？嚇到了嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"저래봬도 심성은 바른 아이니까 너무 나쁘게 생각하지 말아줘.","JPN":"ああ見えても、根はいい子だから。あまり悪く思わないで。","ENG":"She's a good kid, so don't take anything she says to heart.","TWN":"雖然她看起來那樣，但她心地善良，不要把她想得太壞。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"나이엘이라고 했지……? 저 아이…….\xA0","JPN":"ナイエル、って言ったよね……？　あの子……\xA0","ENG":"Naielle, was it...? That girl...?\xA0","TWN":"你說奈爾……？那孩子……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}}]`);export{e as default};